    map<char, int> frequencies;
    for (char c : s) {
        frequencies[c]++;
    }

    int64_t total_diff_sum = 0;

    // To ensure we process each pair only once, we iterate over unique characters
    // and only process (c, m) if c <= m (lexicographically).

    // We need to iterate over the keys of the map.
    // Since std::map is sorted by key, iterating through it naturally provides an ordered sequence.

    for (auto const& [c, freq_c] : frequencies) {
