        // but we check this just in case, although based on math, it shouldn't happen.
        if (c == m) {
            // Contribution is |freq(c) - freq(c)| = 0. Skip.
            continue;
        }

        // Get frequency of mirror character m. It might not be in the string.
        int freq_m = 0;
        if (frequencies.count(m)) {
            freq_m = frequencies.at(m);
        }

        // Calculate absolute difference: |freq(c) - freq(m)|
        int64_t diff = abs(freq_c - freq_m);

        // Add to total sum
        total_diff_sum += diff;
    }

    return total_diff_sum;
