    let frequencies = HashMap.new<Char, Int>()
    for c in s.chars {
        frequencies[c] = (frequencies[c] ?? 0) + 1
    }

    let total_diff: Int64 = 0
    // Tracks characters whose mirror pair calculation has already been accounted for
    let processed = HashMap.new<Char, Bool>()

    // Iterate over all unique characters present in the string
    for c in frequencies.keys {
        if processed[c] == true {
            continue
        }

        // Find the mirror character m
        let m = get_mirror(c)

        // Get frequencies (defaulting to 0 if not present)
        let freq_c = frequencies[c] ?? 0
        let freq_m = frequencies[m] ?? 0

